// lookup.service.ts
import { Injectable } from '@nestjs/common';

@Injectable()
export class LookupService {
  private countries = ['USA', 'Canada', 'Mexico'];
  private devices = ['Laptop', 'Tablet', 'Smartphone'];
  private institutions = ['University A', 'College B', 'School C'];

  getCountries(filter?: string) {
    return this.filterData(this.countries, filter);
  }

  getDevices(filter?: string) {
    return this.filterData(this.devices, filter);
  }

  getInstitutions(filter?: string) {
    return this.filterData(this.institutions, filter);
  }

  private filterData(data: string[], filter?: string) {
    if (!filter) return data;
    return data.filter(item => item.toLowerCase().includes(filter.toLowerCase()));
  }
}

